def gen(rng, size):
    n = max(2, min(size, 30))
    nodes = list(range(1, n + 1))
    rng.shuffle(nodes)
    parent = {nodes[0]: None}
    for i in range(1, n):
        parent[nodes[i]] = nodes[rng.randint(0, i - 1)]
    ancestors_of = {nodes[0]: set()}
    for i in range(1, n):
        v = nodes[i]
        p = parent[v]
        ancestors_of[v] = ancestors_of[p] | {p}
    pairs = []
    for v in nodes:
        for a in ancestors_of[v]:
            pairs.append([min(a, v), max(a, v)])
    return [pairs]

