class Solution:
    def checkWays(self, pairs):
        from collections import defaultdict
        from itertools import product

        adj = defaultdict(set)
        for x, y in pairs:
            adj[x].add(y)
            adj[y].add(x)
        nodes = sorted(adj.keys())
        n = len(nodes)
        pair_set = set((min(x, y), max(x, y)) for x, y in pairs)

        def fast_check():
            order = sorted(nodes, key=lambda v: -len(adj[v]))
            if len(adj[order[0]]) != n - 1:
                return 0
            multiple = False
            for v in order[1:]:
                deg_v = len(adj[v])
                parent = None
                parent_deg = None
                for u in adj[v]:
                    du = len(adj[u])
                    if du >= deg_v and (parent is None or du < parent_deg):
                        parent = u
                        parent_deg = du
                if parent is None:
                    return 0
                if parent_deg == deg_v:
                    multiple = True
                for w in adj[v]:
                    if w != parent and w not in adj[parent]:
                        return 0
            return 2 if multiple else 1

        if n > 6:
            return fast_check()

        count = 0
        for root in nodes:
            others = [v for v in nodes if v != root]
            m = len(others)
            for assignment in product(range(n), repeat=m):
                parent = {root: None}
                ok = True
                for i, v in enumerate(others):
                    p = nodes[assignment[i]]
                    if p == v:
                        ok = False
                        break
                    parent[v] = p
                if not ok:
                    continue
                valid = True
                for v in others:
                    seen = set()
                    cur = v
                    steps = 0
                    while cur != root:
                        if cur in seen or steps > n:
                            valid = False
                            break
                        seen.add(cur)
                        cur = parent[cur]
                        steps += 1
                    if not valid:
                        break
                if not valid:
                    continue
                children = defaultdict(list)
                for v in others:
                    children[parent[v]].append(v)
                ancestors_of = {root: frozenset()}
                order_bfs = [root]
                qi = 0
                while qi < len(order_bfs):
                    u = order_bfs[qi]
                    qi += 1
                    for c in children[u]:
                        ancestors_of[c] = ancestors_of[u] | {u}
                        order_bfs.append(c)
                if len(order_bfs) != n:
                    continue
                implied = set()
                for v in nodes:
                    for a in ancestors_of[v]:
                        implied.add((min(a, v), max(a, v)))
                if implied == pair_set:
                    count += 1
        if count == 0:
            return 0
        return 1 if count == 1 else 2

