var checkWays = function(pairs) {
    const adj = new Map();
    const add = (a, b) => {
        if (!adj.has(a)) adj.set(a, new Set());
        adj.get(a).add(b);
    };
    for (const [x, y] of pairs) {
        add(x, y);
        add(y, x);
    }
    const nodes = Array.from(adj.keys());
    const n = nodes.length;
    const order = nodes.slice().sort((a, b) => adj.get(b).size - adj.get(a).size);
    if (adj.get(order[0]).size !== n - 1) return 0;
    let multiple = false;
    for (let idx = 1; idx < order.length; idx++) {
        const v = order[idx];
        const degV = adj.get(v).size;
        let parent = null;
        let parentDeg = null;
        for (const u of adj.get(v)) {
            const du = adj.get(u).size;
            if (du >= degV && (parent === null || du < parentDeg)) {
                parent = u;
                parentDeg = du;
            }
        }
        if (parent === null) return 0;
        if (parentDeg === degV) multiple = true;
        for (const w of adj.get(v)) {
            if (w !== parent && !adj.get(parent).has(w)) return 0;
        }
    }
    return multiple ? 2 : 1;
};
